using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public record TicketRequest(string Subject, string Description, int Priority);

public record PredictionResponse(string PredictedCategory, Dictionary<string, float> Probabilities);

public record EvaluationResponse(
    double MicroAccuracy,
    double MacroAccuracy,
    double LogLoss,
    double LogLossReduction,
    string ConfusionMatrix);

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly string[] _categoryLabels;
    private readonly string _dataPath;

    public TicketClassifierService(string dataPath)
    {
        _dataPath = dataPath;
        _mlContext = new MLContext(seed: 42);
        _model = TrainModel();
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);
        _categoryLabels = GetCategoryLabels();
    }

    private ITransformer TrainModel()
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        return pipeline.Fit(data);
    }

    private string[] GetCategoryLabels()
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var labelPipeline = _mlContext.Transforms.Conversion
            .MapValueToKey("Label", nameof(TicketData.Category));
        var labelModel = labelPipeline.Fit(data);
        var schema = labelModel.GetOutputSchema(data.Schema);
        var labelColumn = schema["Label"];

        var keyType = labelColumn.Type.AsKey;
        var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
        labelModel.GetOutputSchema(data.Schema)["Label"].GetKeyValues(ref labelBuffer);

        return labelBuffer.DenseValues().Select(v => v.ToString()).ToArray();
    }

    public PredictionResponse Predict(TicketRequest request)
    {
        var ticket = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticket);

        var probabilities = new Dictionary<string, float>();
        for (int i = 0; i < _categoryLabels.Length; i++)
        {
            probabilities[_categoryLabels[i]] = i < prediction.Score.Length
                ? prediction.Score[i]
                : 0f;
        }

        return new PredictionResponse(prediction.Category, probabilities);
    }

    public EvaluationResponse Evaluate()
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Use cross-validation for small datasets to get meaningful metrics
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        var cvResults = _mlContext.MulticlassClassification
            .CrossValidate(data, pipeline, numberOfFolds: 3);

        var avgMicro = cvResults.Average(r => r.Metrics.MicroAccuracy);
        var avgMacro = cvResults.Average(r => r.Metrics.MacroAccuracy);
        var avgLogLoss = cvResults.Average(r => r.Metrics.LogLoss);
        var avgLogLossReduction = cvResults.Average(r => r.Metrics.LogLossReduction);

        // Also evaluate on the full training set for the confusion matrix
        var predictions = _model.Transform(data);
        var fullMetrics = _mlContext.MulticlassClassification.Evaluate(predictions, "Label");

        return new EvaluationResponse(
            Math.Round(avgMicro, 4),
            Math.Round(avgMacro, 4),
            Math.Round(avgLogLoss, 4),
            Math.Round(avgLogLossReduction, 4),
            fullMetrics.ConfusionMatrix.GetFormattedConfusionTable());
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController : ControllerBase
{
    private readonly TicketClassifierService _service;

    public TicketClassifierController(TicketClassifierService service)
    {
        _service = service;
    }

    [HttpPost("predict")]
    public ActionResult<PredictionResponse> Predict([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject))
            return BadRequest("Subject is required.");

        if (string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Description is required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var result = _service.Predict(request);
        return Ok(result);
    }

    [HttpGet("evaluate")]
    public ActionResult<EvaluationResponse> Evaluate()
    {
        var result = _service.Evaluate();
        return Ok(result);
    }
}

