        _mlContext = new MLContext(seed: 42);
        _model = TrainModel();
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);
        _categoryLabels = GetCategoryLabels();
    }

    private ITransformer TrainModel()
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        return pipeline.Fit(data);
    }

    private string[] GetCategoryLabels()
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var labelPipeline = _mlContext.Transforms.Conversion
            .MapValueToKey("Label", nameof(TicketData.Category));
        var labelModel = labelPipeline.Fit(data);
        var schema = labelModel.GetOutputSchema(data.Schema);
        var labelColumn = schema["Label"];

        var keyType = labelColumn.Type.AsKey;
        var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
        labelModel.GetOutputSchema(data.Schema)["Label"].GetKeyValues(ref labelBuffer);

        return labelBuffer.DenseValues().Select(v => v.ToString()).ToArray();
    }

    public PredictionResponse Predict(TicketRequest request)
    {
        var ticket = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticket);

        var probabilities = new Dictionary<string, float>();
        for (int i = 0; i < _categoryLabels.Length; i++)
        {
            probabilities[_categoryLabels[i]] = i < prediction.Score.Length
                ? prediction.Score[i]
                : 0f;
        }

        return new PredictionResponse(prediction.Category, probabilities);
    }

    public EvaluationResponse Evaluate()
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Use cross-validation for small datasets to get meaningful metrics
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketData.Subject)))
