            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        var cvResults = _mlContext.MulticlassClassification
            .CrossValidate(data, pipeline, numberOfFolds: 3);

        var avgMicro = cvResults.Average(r => r.Metrics.MicroAccuracy);
        var avgMacro = cvResults.Average(r => r.Metrics.MacroAccuracy);
        var avgLogLoss = cvResults.Average(r => r.Metrics.LogLoss);
        var avgLogLossReduction = cvResults.Average(r => r.Metrics.LogLossReduction);

        // Also evaluate on the full training set for the confusion matrix
        var predictions = _model.Transform(data);
        var fullMetrics = _mlContext.MulticlassClassification.Evaluate(predictions, "Label");

        return new EvaluationResponse(
            Math.Round(avgMicro, 4),
            Math.Round(avgMacro, 4),
            Math.Round(avgLogLoss, 4),
            Math.Round(avgLogLossReduction, 4),
            fullMetrics.ConfusionMatrix.GetFormattedConfusionTable());
    }
}

